pipeline.evaluate:
(async () => {
  const res = await fetch('https://api.bilibili.com/x/web-interface/popular?ps=${{ args.limit }}&pn=1', {
    credentials: 'include'
  });
  const data = await res.json();
  return (data?.data?.list || []).map((item) => ({
    title: item.title,
    author: item.owner?.name,
    play: item.stat?.view,
    danmaku: item.stat?.danmaku,
  }));
})()
